// String returns the pylabview name when known, otherwise a `FieldTag(N)` fallback.
func (t FieldTag) String() string {
	if name, ok := fieldTagNames[t]; ok {
		return name
	}
	return fmt.Sprintf("FieldTag(%d)", int(t))
}

